+		if err != nil {
+			return err
+		}
+		defer r.Close()
+
+		w, err := newObj.Writer()
+		if err != nil {
+			return err
+		}
+		if _, err := io.Copy(w, r); err != nil {
+			_ = w.Close()
+			return err
+		}
+		if err := w.Close(); err != nil {
+			return err
+		}
+		_, err = dst.SetEncodedObject(newObj)
+		return err
+	}); err != nil {
